import { test, expect } from '@playwright/test';

test.describe('Shopping Cart Checkout', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/cart');
    await expect(page.getByRole('heading', { name: 'Your Cart' })).toBeVisible();
  });

  test('successful payment with valid card', async ({ page }) => {
    await page.getByRole('button', { name: 'Checkout' }).click();
    await page.getByLabel('Card number').fill('4242424242424242');
    await page.getByLabel('Expiry').fill('12/28');
    await page.getByLabel('CVC').fill('123');
    await page.getByRole('button', { name: 'Pay Now' }).click();
    await expect(page.getByText('Order Confirmed')).toBeVisible({ timeout: 10000 });
  });

  test('payment failure shows error and preserves cart', async ({ page }) => {
    await page.getByRole('button', { name: 'Checkout' }).click();
    await page.getByLabel('Card number').fill('4000000000000002');
    await page.getByLabel('Expiry').fill('12/28');
    await page.getByLabel('CVC').fill('123');
    await page.getByRole('button', { name: 'Pay Now' }).click();
    await expect(page.getByText('Payment declined')).toBeVisible();
    await page.goBack();
    await expect(page.getByRole('heading', { name: 'Your Cart' })).toBeVisible();
  });

  [1, 99].forEach((qty) => {
    test(`accepts valid quantity: ${qty}`, async ({ page }) => {
      await page.getByLabel('Quantity').fill(String(qty));
      await expect(page.getByLabel('Quantity')).toHaveValue(String(qty));
    });
  });

  [0, 100, -1].forEach((qty) => {
    test(`rejects invalid quantity: ${qty}`, async ({ page }) => {
      await page.getByLabel('Quantity').fill(String(qty));
      await page.getByRole('button', { name: 'Update' }).click();
      await expect(page.getByText(/invalid quantity/i)).toBeVisible();
    });
  });
});
